def view_content(current_user_id: int, content_id: int) -> str:
    """
    Return the title of the content if:
      - the current user is an admin, or
      - the user's subscription level matches the content's required level.
    Otherwise, return "Access Denied".
    """
    user = USERS.get(current_user_id)
    if not user:
        return "Access Denied"

    content = CONTENT.get(content_id)
    if content is None:
        return "Content Not Found"

    if user.get("role") == "admin":
        return content.get("title", "Content Not Found")

    if user.get("subscription_level") == content.get("required_level"):
        return content.get("title", "Content Not Found")

    return "Access Denied"

